// ─── RESOURCE RING ────────────────────────────────────────────────
function ResourceRing({ label, value, detail, percent, color }: { label: string; value: string; detail: string; percent: number; color: string }) {
  const stroke: Record<string, string> = { cyan: "stroke-cyan-400", violet: "stroke-violet-400", green: "stroke-green-400", amber: "stroke-amber-400" };
  const text: Record<string, string> = { cyan: "text-cyan-400", violet: "text-violet-400", green: "text-green-400", amber: "text-amber-400" };
  const glow: Record<string, string> = { cyan: "drop-shadow-[0_0_4px_rgba(34,211,238,0.4)]", violet: "drop-shadow-[0_0_4px_rgba(167,139,250,0.4)]", green: "drop-shadow-[0_0_4px_rgba(74,222,128,0.4)]", amber: "drop-shadow-[0_0_4px_rgba(251,191,36,0.4)]" };
  const r = 42;
  const c = 2 * Math.PI * r;
  const offset = c - (Math.min(percent, 100) / 100) * c;
  return (
    <div className="bg-zinc-900/90 rounded-lg border border-zinc-700/60 p-4 flex flex-col items-center relative">
      <div className="absolute top-2 right-2"><StatusLamp healthy={percent < 90} /></div>
      <div className="absolute top-2 left-2"><ConsoleID id={`SYS-${label.slice(0, 3).toUpperCase()}`} /></div>
      <svg width="100" height="100" className={`${glow[color]} -rotate-90`}>
        <circle cx="50" cy="50" r={r} fill="none" stroke="#27272a" strokeWidth="6" />
        <circle cx="50" cy="50" r={r} fill="none" className={stroke[color]} strokeWidth="6" strokeDasharray={c} strokeDashoffset={offset} strokeLinecap="round" />
        <circle cx="50" cy="50" r={r + 5} fill="none" stroke="#3f3f46" strokeWidth="1" opacity="0.4" />
      </svg>
      <div className={`text-xl font-black ${text[color]} -mt-[62px] mb-[32px]`} style={{ fontFamily: "'Orbitron', monospace" }}>{value}</div>
      <LCARSLabelStrip label={label} color={text[color]} />
      <div className="text-[10px] text-zinc-500">{detail}</div>
    </div>
  );
}

// ─── SEGMENTED BAR ────────────────────────────────────────────────
function SegmentedBar({ label, value, max, color = "amber" }: { label: string; value: number; max: number; color?: string }) {
  const pct = max > 0 ? (value / max) * 100 : 0;
  const bg: Record<string, string> = { amber: "bg-amber-500", cyan: "bg-cyan-500", violet: "bg-violet-500", green: "bg-green-500" };
  const text: Record<string, string> = { amber: "text-amber-400", cyan: "text-cyan-400", violet: "text-violet-400", green: "text-green-400" };
  const segments = 20;
  const filled = Math.round((pct / 100) * segments);
  return (
    <div className="flex items-center gap-3">
      <div className={`text-[10px] font-bold tracking-wider ${text[color]} w-36 text-right`} style={{ fontFamily: "'Orbitron', monospace" }}>{label}</div>
      <div className="flex gap-[2px] flex-1">
        {Array.from({ length: segments }).map((_, i) => (
          <div key={i} className={`h-3 flex-1 rounded-sm ${i < filled ? bg[color] + " opacity-80" : "bg-zinc-800"}`} />
        ))}
      </div>
      <div className={`text-[10px] font-bold ${text[color]} w-20`} style={{ fontFamily: "'Orbitron', monospace" }}>{value} / {max}</div>
    </div>
  );
}

